import { createLogger, format, transports } from 'winston';
import { v4 as uuidv4 } from 'uuid';
import expressWinston from 'express-winston';

const { combine, timestamp, printf, json } = format;

// Custom format for logs
const logFormat = printf(({ level, message, timestamp, requestId }) => {
  return `${timestamp} [${requestId}] ${level}: ${message}`;
});

// Create a logger instance
const logger = createLogger({
  level: 'info',
  format: combine(
    timestamp(),
    logFormat,
    json()
  ),
  defaultMeta: { service: 'user-service' },
  transports: [
    new transports.Console(),
    new transports.File({ filename: 'logs/error.log', level: 'error' }),
    new transports.File({ filename: 'logs/combined.log' })
  ],
});

// Middleware to add `requestId` to each log entry
export const requestLogger = expressWinston.logger({
  transports: [
    new transports.Console()
  ],
  format: combine(
    expressWinston.requestWhitelist.concat(['requestId']),
    timestamp(),
    logFormat
  ),
  requestFilter: function (req, propName) {
    // Add requestId to each request
    req.requestId = req.headers['x-request-id'] || uuidv4();
    return req[propName];
  },
  expressFormat: true,
  meta: true,
  msg: "HTTP {{req.method}} {{req.url}}",
});

export default logger;
